// ── Helpers ──────────────────────────────────────────────────

let tmpDir: string;

beforeEach(async () => {
  tmpDir = await fs.mkdtemp(path.join(os.tmpdir(), 'forge-plan-test-'));
  await fs.mkdir(path.join(tmpDir, '.forge'), { recursive: true });
});

afterEach(async () => {
  await fs.rm(tmpDir, { recursive: true, force: true });
});

// ── Planning prompt structure ─────────────────────────────────

describe('plan-mode prompt construction', () => {
  // These tests verify the planning prompt template by reading run.ts source.
  // The critical sections required by the spec must be present.

  test('run.ts source includes disallowedTools enforcement for planOnly', async () => {
    const runSrc = await fs.readFile(
      path.join(import.meta.dir, 'run.ts'),
      'utf-8',
    );
    // Verify SDK-level tool restriction is set for plan-only mode
    expect(runSrc).toContain("disallowedTools: ['Write', 'Edit']");
    expect(runSrc).toContain('planOnly');
  });

  test('run.ts planning prompt includes required output sections', async () => {
    const runSrc = await fs.readFile(
      path.join(import.meta.dir, 'run.ts'),
      'utf-8',
    );
    // The planning prompt must include all required structured sections
    expect(runSrc).toContain('Goal Summary');
    expect(runSrc).toContain('File Inventory');
    expect(runSrc).toContain('Dependency Analysis');
    expect(runSrc).toContain('Implementation Steps');
    expect(runSrc).toContain('Risk Assessment');
  });

  test('run.ts planning prompt instructs read-only tools only', async () => {
    const runSrc = await fs.readFile(
      path.join(import.meta.dir, 'run.ts'),
      'utf-8',
    );
    // Planning mode prompt should explicitly restrict to read-only operations
    expect(runSrc).toContain('read-only');
    expect(runSrc).toContain('Do not create, modify, or delete files');
  });

  test('run.ts verification is skipped for planOnly', async () => {
    const runSrc = await fs.readFile(
      path.join(import.meta.dir, 'run.ts'),
      'utf-8',
    );
    // Verification must be skipped for plan-only runs
    expect(runSrc).toContain('planOnly');
    // The guard condition for verification
    expect(runSrc).toMatch(/!planOnly/);
  });

  test('run.ts uses planModel when planOnly is set', async () => {
    const runSrc = await fs.readFile(
      path.join(import.meta.dir, 'run.ts'),
      'utf-8',
    );
    // Plan model override must be applied
    expect(runSrc).toContain('planModel');
    expect(runSrc).toContain('planOnly && planModel');
  });
});

