// ── Bash tool available in plan mode (read-only exploration) ──

describe('plan-mode tool restrictions', () => {
  test('only Write and Edit are blocked (not Bash)', async () => {
    const runSrc = await fs.readFile(
      path.join(import.meta.dir, 'run.ts'),
      'utf-8',
    );
    // Should block Write and Edit but NOT Bash
    expect(runSrc).toContain("'Write'");
    expect(runSrc).toContain("'Edit'");
    // Bash should not be in the disallowedTools list
    const disallowedMatch = runSrc.match(/disallowedTools:\s*\[([^\]]+)\]/);
    if (disallowedMatch) {
      expect(disallowedMatch[1]).not.toContain('Bash');
    }
  });
});
